import React, { useState } from "react";
import axios from "axios";
import { getSongsByMood } from "./api";

function App() {
  const [songs, setSongs] = useState([]);
  const [favorites, setFavorites] = useState([]);
  const [loading, setLoading] = useState(false);

  const BASE_URL = "http://127.0.0.1:5000";

  // 🎧 GET SONGS BY MOOD
  const fetchSongs = async (mood) => {
    try {
      setLoading(true);
      const res = await getSongsByMood(mood);
      setSongs(res.data || []);
    } catch (err) {
      console.log("Mood error:", err);
      setSongs([]);
    } finally {
      setLoading(false);
    }
  };

  // 🔍 SEARCH SONGS
  const searchSongs = async (text) => {
    try {
      if (!text) {
        setSongs([]);
        return;
      }

      setLoading(true);
      const res = await axios.get(`${BASE_URL}/search/${text}`);
      setSongs(res.data || []);
    } catch (err) {
      console.log("Search error:", err);
      setSongs([]);
    } finally {
      setLoading(false);
    }
  };

  // ❤️ FAVORITES
  const toggleFavorite = (title) => {
    setFavorites((prev) =>
      prev.includes(title)
        ? prev.filter((s) => s !== title)
        : [...prev, title]
    );
  };

  return (
    <div
      style={{
        textAlign: "center",
        minHeight: "100vh",
        padding: "20px",
        background: "linear-gradient(to right, #0f2027, #203a43, #2c5364)",
        color: "white"
      }}
    >
      <h1>🎧 Mood Music App</h1>

      {/* SEARCH */}
      <input
        type="text"
        placeholder="🔍 Search songs..."
        onChange={(e) => searchSongs(e.target.value)}
        style={{
          padding: "10px",
          width: "250px",
          borderRadius: "10px",
          border: "none",
          marginBottom: "20px"
        }}
      />

      {/* MOOD BUTTONS */}
      <div>
        <button onClick={() => fetchSongs("happy")}>Happy 😊</button>
        <button onClick={() => fetchSongs("sad")}>Sad 😢</button>
        <button onClick={() => fetchSongs("love")}>Love ❤️</button>
        <button onClick={() => fetchSongs("relax")}>Relax 😌</button>
      </div>

      {/* LOADING */}
      {loading && <p>Loading songs...</p>}

      {/* SONG LIST */}
      <h2>🎶 Songs</h2>

      {songs.length === 0 && !loading ? (
        <p>Select mood or search songs</p>
      ) : (
        songs.map((song, i) => (
          <div
            key={i}
            style={{
              background: "rgba(255,255,255,0.1)",
              margin: "10px auto",
              padding: "15px",
              width: "350px",
              borderRadius: "12px"
            }}
          >
            <h3>{song.title}</h3>
            <p>{song.artist}</p>

            {/* AUDIO PLAYER */}
            {song.url && (
              <audio controls style={{ width: "100%" }}>
                <source src={song.url} type="audio/mp3" />
              </audio>
            )}

            {/* FAVORITE */}
            <button
              onClick={() => toggleFavorite(song.title)}
              style={{
                background: "transparent",
                border: "none",
                fontSize: "18px",
                cursor: "pointer",
                color: favorites.includes(song.title) ? "red" : "white"
              }}
            >
              ❤️
            </button>
          </div>
        ))
      )}

      {/* FAVORITES */}
      <h2>❤️ Favorites</h2>

      {favorites.length === 0 ? (
        <p>No favorites yet</p>
      ) : (
        favorites.map((song, i) => <p key={i}>⭐ {song}</p>)
      )}
    </div>
  );
}

export default App;
